css:
.loader {
  display: inline-block;
  width: 52px;
  height: 52px;
  border-radius: 50%;
  border: 4px solid color-mix(in srgb, var(--loader-color) 18%, transparent);
  border-top-color: var(--loader-color);
  animation: spin 0.9299999999999999s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }
